INSERT INTO matches (id, property_id, demand_id, score, status, created_at, updated_at, insights) VALUES ('match-pituba', 'prop-pituba-1', 'dem-pituba-3', 95, 'Novo', '2026-05-29 18:20:11.000', '2026-05-30 00:48:53.000', '{"explanation":"Este apartamento na Pituba é uma escolha ideal para o seu cliente, pois se encaixa perfeitamente nas suas necessidades: possui 3 quartos, 2 vagas e está dentro do orçamento de R$ 750.000, que é inferior ao máximo de R$ 800.000 estipulado. Além disso, a varanda gourmet, que é um requisito específico do cliente, é um destaque deste imóvel reformado.","advice":"Sugiro que os corretores pactuem um split de comissão de 50/50 conforme garantido em contrato e agendem uma visita o mais breve possível para atender à urgência do cliente. É importante compartilhar material visual do imóvel e informações relevantes para que ambos possam apresentar o apartamento de forma convincente.","scoreExplanation":"O score de 95% de compatibilidade foi alcançado por conta da sinergia entre as características solicitadas pelo cliente e as disponibilizadas pelo imóvel, incluindo a localização desejada, número de quartos e vagas. A pequena diferença vem do fato de que o cliente buscava especificamente uma varanda gourmet, embora o imóvel ofereça exatamente essa comodidade."}');
