INSERT INTO properties (id, title, type, purpose, price, city, neighborhood, description, bedrooms, bathrooms, parking_spots, area, commission, accepts_partnership, condo_fee, iptu, virtual_tour, video_url, status, created_at, created_by, updated_at, photos) VALUES ('prop-itaim-2', 'Studio de Luxo Mobiliado de 40m² a uma quadra do Parque do Povo', 'apartamento', 'venda', '1100000.00', 'São Paulo', 'Itaim Bibi', 'Excelente oportunidade para investidor ou moradia com praticidade no coração do Itaim Bibi. Studio totalmente decorado e mobiliado por arquiteto renomado. Cozinha planejada com eletrodomésticos embutidos, ar condicionado inverter central, cama queen com armário espelhado de alto acabamento e banheiro espaçoso revestido com pastilhas finas. 1 vaga de estacionamento. Condomínio com lavanderia compartilhada, academia profissional de última geração administrada por assessoria esportiva, piscina climatizada de raia e espaço coworking de uso livre.', 1, 1, 1, '40.00', '5% de comissão (partilha rigorosa de 50% pro corretor parceiro)', 1, '500.00', '900.00', NULL, NULL, 'Ativo', '2026-05-24 18:20:10.000', 'broker-ana', '2026-05-29 19:59:47.000', '["https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?w=800&auto=format&fit=crop&q=80","https://images.unsplash.com/photo-1560185007-cde436f6a4d0?w=800&auto=format&fit=crop&q=80","https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?w=800&auto=format&fit=crop&q=80"]');
INSERT INTO properties (id, title, type, purpose, price, city, neighborhood, description, bedrooms, bathrooms, parking_spots, area, commission, accepts_partnership, condo_fee, iptu, virtual_tour, video_url, status, created_at, created_by, updated_at, photos) VALUES ('prop-pituba-1', 'Apartamento Reformado 3 Qts com Varanda Gourmet na Pituba', 'apartamento', 'venda', '750000.00', 'Salvador', 'Pituba', 'Maravilhoso apartamento andar alto na Pituba, reformado com piso em porcelanato 80x80, teto rebaixado com iluminação planejada de LED. Ampla sala de estar integrada a uma incrível varanda gourmet envidraçada com churrasqueira ecológica. São 3 quartos (1 suíte com closet), cozinha equipada, dependência completa de serviço, 2 garagens cobertas e soltas. Prédio com infraestrutura de lazer: piscina, sauna, quiosque, brinquedoteca, portaria 24h automatizada e hall decorado.', 3, 3, 2, '95.00', '6% de comissão (partilha de 50/50 garantida em contrato)', 1, '780.00', '1500.00', NULL, NULL, 'Ativo', '2026-05-26 18:20:10.000', 'broker-renato', '2026-05-29 20:01:59.000', '["https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?w=800&auto=format&fit=crop&q=80","https://images.unsplash.com/photo-1502672260266-1c1ef2d93688?w=800&auto=format&fit=crop&q=80","https://images.unsplash.com/photo-1493809842364-78817add7ffb?w=800&auto=format&fit=crop&q=80","https://images.unsplash.com/photo-1560185893-a55cbc8c57e8?w=800&auto=format&fit=crop&q=80"]');
